McfgBassAddress = None

def GetBaseAddress ():

  from EfiPy2.Lib.Acpi.AcpiRetrieve   import ExtractTable
  from EfiPy2.Lib.Acpi.AcpiMcfgParser import AcpiMcfgParser

  AcpiRaw = ExtractTable (b'MCFG', 0)
  AcpiObj, AcpiType = AcpiMcfgParser (AcpiRaw)

  return AcpiObj.McfgDesc.BaseAddress

def GetPciEcam (Bus = 0, Device = 0, Function = 0):

  global McfgBassAddress

  import EfiPy2.MdePkg.IndustryStandard.Pci as pci

  if McfgBassAddress is None:
      McfgBassAddress = GetBaseAddress ()

  return McfgBassAddress + pci.PCI_ECAM_ADDRESS (Bus, Device, Function, 0)
